            [allowZoneSelection]="true"
            [allowMarkdown]="true"
            [allowExport]="true"
            [allowContinueAfterEnd]="false"
            [quickPrompts]="['Reformule', 'Plus de d\xE9tails', 'R\xE9sume']"
            endMarker="[FIN_TCHAT]"
